{
  "name": "CourtConnect",
  "description": "A comprehensive court booking and community platform for badminton, pickleball, and basketball, featuring real-time availability and AI-powered recommendations.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type SportType = 'Badminton' | 'Pickleball' | 'Basketball';

export interface Court {
  id: string;
  name: string;
  type: SportType;
  image: string;
  price: number;
  rating: number;
  location: string;
  coordinates: { lat: number; lng: number };
  amenities: string[];
  description: string;
}

export interface BookingDetails {
  courtId: string;
  date: string;
  timeSlot: string;
  totalAmount: number;
  userName: string;
  userEmail: string;
}

export interface Tournament {
  id: string;
  title: string;
  sport: SportType;
  date: string;
  status: 'Open' | 'Closed' | 'Ongoing';
  teams: number;
}

{
  "name": "SportSync",
  "description": "SportSync is a web platform that replaces manual scheduling with instant online booking for badminton, pickleball, and basketball courts.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { COURTS } from './constants';
import { Court, SportType, Tournament } from './types';

// Mock AI Assistant
const SportBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: "Hi! I'm your SportSync Assistant. Need help finding a court or learning rules?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: (process.env as any).API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are SportSync Bot, a helpful sports court booking assistant. 
        Context: We offer Badminton, Pickleball, and Basketball. 
        User says: ${userMsg}`,
        config: {
          systemInstruction: "Be concise, energetic, and helpful. Recommend courts based on common sports needs."
        }
      });
      setMessages(prev => [...prev, { role: 'bot', text: response.text || "I'm having trouble connecting right now." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "Sorry, I'm offline for a moment. Try booking manually!" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-50">
      {isOpen ? (
        <div className="w-80 md:w-96 h-[500px] bg-white rounded-2xl shadow-2xl flex flex-col overflow-hidden border border-slate-200">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <i className="fas fa-robot text-xl"></i>
              <span className="font-bold">SportBot AI</span>
            </div>
            <button onClick={() => setIsOpen(false)}><i className="fas fa-times"></i></button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${m.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-800'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && <div className="text-slate-400 text-xs italic">Bot is thinking...</div>}
          </div>
          <div className="p-3 border-t flex gap-2">
            <input 
              className="flex-1 border rounded-full px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
              placeholder="Ask me anything..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button 
              onClick={handleSend}
              className="bg-indigo-600 text-white w-10 h-10 rounded-full flex items-center justify-center hover:bg-indigo-700 transition"
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-14 h-14 bg-indigo-600 text-white rounded-full shadow-lg flex items-center justify-center hover:scale-110 transition-transform"
        >
          <i className="fas fa-comment-dots text-2xl"></i>
        </button>
      )}
    </div>
  );
};

const Logo = () => (
  <div className="flex items-center gap-2 font-extrabold text-2xl tracking-tighter">
    <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center text-white rotate-3">
      <i className="fas fa-bolt"></i>
    </div>
    <span className="text-slate-900">Sport<span className="text-indigo-600">Sync</span></span>
  </div>
);

