import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI } from "@google/genai";
import { COURTS } from './constants';
import { Court, SportType } from './types';

// SportSync Bot - AI Assistant
const SportBot = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'bot', text: string}[]>([
    { role: 'bot', text: "Hello! I'm your SportSync Assistant. Ready to find the perfect court on the green?" }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: (process.env as any).API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `You are SportSync Bot. 
        Context: Professional court booking for Badminton, Pickleball, and Basketball.
        Visuals: Primary Green (#005F02) is our entire background identity.
        User: ${userMsg}`,
        config: {
          systemInstruction: "Be authoritative yet friendly. Emphasize professionalism and efficiency. Your personality matches the deep green background: stable, premium, and focused on sport."
        }
      });
      setMessages(prev => [...prev, { role: 'bot', text: response.text || "I'm having a connection timeout." }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'bot', text: "I'm currently offline. Please book manually below!" }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed bottom-8 right-8 z-50">
      {isOpen ? (
        <div className="w-80 md:w-96 h-[520px] bg-white rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-cream/20 animate-in fade-in slide-in-from-bottom-6 duration-300">
          <div className="bg-primary p-5 text-cream flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-8 h-8 bg-cream rounded-lg flex items-center justify-center text-primary">
                <i className="fas fa-robot text-sm"></i>
              </div>
              <span className="font-bold tracking-tight">SportSync Assistant</span>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:rotate-90 transition-transform"><i className="fas fa-times"></i></button>
          </div>
          <div ref={scrollRef} className="flex-1 overflow-y-auto p-5 space-y-4 bg-cream/10">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-sm shadow-sm ${m.role === 'user' ? 'bg-primary text-cream' : 'bg-white text-slate-800 border border-cream'}`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isLoading && <div className="text-primary/60 text-xs italic animate-pulse px-2">Assistant is typing...</div>}
          </div>
          <div className="p-4 bg-white border-t border-cream flex gap-2">
            <input 
              className="flex-1 border-2 border-cream/50 rounded-xl px-4 py-2 text-sm focus:outline-none focus:border-primary transition-colors text-slate-900"
              placeholder="Ask me anything..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            />
            <button 
              onClick={handleSend}
              className="bg-primary text-cream w-11 h-11 rounded-xl flex items-center justify-center hover:bg-primary-dark transition-all active:scale-95 shadow-lg shadow-primary/20"
            >
              <i className="fas fa-paper-plane"></i>
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-cream text-primary rounded-2xl shadow-2xl flex items-center justify-center hover:scale-110 transition-all active:scale-95 border-2 border-white shadow-primary/40"
        >
          <i className="fas fa-comment-alt text-2xl"></i>
        </button>
      )}
    </div>
  );
};

