    <div className="bg-white rounded-[4rem] overflow-hidden shadow-sm hover:shadow-2xl transition-all duration-700 group border border-slate-100 flex flex-col h-full active:scale-[0.98]">
      <div className="relative h-72 overflow-hidden">
        <img src={court.image} alt={court.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 grayscale-[40%] group-hover:grayscale-0" />
        <div className="absolute inset-0 bg-slate-900/10 group-hover:bg-transparent transition-colors"></div>
        <div className="absolute top-8 left-8">
           <span className="bg-white/90 backdrop-blur-md text-primary px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] shadow-xl border border-slate-100 inline-block">{court.type}</span>
        </div>
        <div className="absolute bottom-8 left-8 bg-primary text-white px-5 py-2 rounded-xl text-[10px] font-black tracking-widest uppercase shadow-xl">
          Verified
        </div>
      </div>
      <div className="p-12 space-y-6 flex-1 flex flex-col bg-white">
        <div className="flex justify-between items-start gap-4">
          <h3 className="font-black text-4xl text-primary group-hover:text-slate-700 transition-colors line-clamp-2 leading-[0.95] tracking-tighter uppercase">{court.name}</h3>
          <div className="flex items-center text-primary text-sm font-black bg-slate-50 px-4 py-2 rounded-2xl border border-slate-200 shadow-sm flex-shrink-0">
            <i className="fas fa-star mr-2 text-primary"></i> {court.rating}
          </div>
        </div>
        <p className="text-slate-400 text-sm font-black line-clamp-1 flex items-center uppercase tracking-widest"><i className="fas fa-map-pin mr-3 text-primary"></i>{court.location}</p>
        <div className="flex flex-wrap gap-3">
          {court.amenities.slice(0, 3).map(a => <span key={a} className="text-[10px] font-black bg-slate-50 text-slate-400 px-5 py-3 rounded-2xl border border-slate-100 group-hover:bg-slate-100 group-hover:text-primary transition-all duration-300 uppercase tracking-tighter">{a}</span>)}
        </div>
        <div className="pt-10 flex items-center justify-between border-t border-slate-100 mt-auto">
          <div>
            <p className="text-4xl font-black text-primary tracking-tighter">${court.price}<span className="text-xs text-slate-300 font-black ml-1 uppercase tracking-widest">/hr</span></p>
          </div>
          <button 
            onClick={onBook}
            className="bg-primary text-white px-10 py-5 rounded-[1.5rem] font-black hover:bg-slate-800 transition-all duration-500 shadow-xl shadow-slate-900/10 active:scale-90 text-xs uppercase tracking-widest"
          >
            BOOK SLOT
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
